import PageLayout from '../layouts/PageLayout.astro';
---

<PageLayout name="L-system garden" back wide>
  <p class="lsystem-intro">Rewrite symbols, then let a turtle walk the result. Tiny local grammar rules become curves, plants, and fractal silhouettes.</p>

  <section class="lsystem-grid" id="lsystem-app">
    <form class="lsystem-card" id="lsystem-form">
      <h2>grammar</h2>
      <label>
        preset
        <select id="lsystem-preset">
          <option value="koch">koch snowflake edge</option>
          <option value="dragon">dragon curve</option>
          <option value="sierpinski">sierpinski arrowhead</option>
          <option value="plant">fractal plant</option>
        </select>
      </label>
      <label>
        axiom
        <input id="lsystem-axiom" type="text" value="F" />
      </label>
      <label>
        rules, one per line
        <textarea id="lsystem-rules" rows="5">F=F+F--F+F</textarea>
      </label>
      <div class="lsystem-two">
        <label>iterations <input id="lsystem-iterations" type="number" min="0" max="8" value="4" /></label>
        <label>angle <input id="lsystem-angle" type="number" min="1" max="180" value="60" /></label>
      </div>
      <button class="toolbar-button" id="lsystem-grow" type="button">grow</button>
      <div class="lsystem-output" id="lsystem-summary" aria-live="polite"></div>
    </form>

    <article class="lsystem-card lsystem-wide">
      <div class="lsystem-head">
        <div>
          <h2>turtle path</h2>
          <p class="lsystem-intro">Commands: <code>F/G</code> draw, <code>f</code> moves, <code>+/-</code> turns, <code>[ ]</code> branches. Use 0 iterations to draw the axiom as raw commands.</p>
        </div>
        <button class="toolbar-button" id="lsystem-download" type="button">copy svg</button>
      </div>
      <div class="lsystem-svg-wrap">
        <svg id="lsystem-plot" role="img" aria-label="L-system turtle drawing"></svg>
      </div>
    </article>
  </section>
</PageLayout>

<style>
  .lsystem-intro,
  .lsystem-card label,
  .lsystem-output { color: var(--muted); }

  .lsystem-grid {
    display: grid;
    grid-template-columns: minmax(17rem, 24rem) minmax(0, 1fr);
    gap: 1rem;
  }

  .lsystem-card {
    border: 1px solid var(--line);
    padding: 1rem;
    display: grid;
    gap: .75rem;
    align-content: start;
  }

  .lsystem-wide { min-width: 0; }

  .lsystem-card h2 {
    font-size: 1rem;
    margin: 0;
  }

  .lsystem-card label {
    display: grid;
    gap: .25rem;
  }

  .lsystem-card input,
  .lsystem-card select,
  .lsystem-card textarea {
    width: 100%;
    padding: .35rem .45rem;
  }

  .lsystem-card textarea {
    min-height: 7rem;
    resize: vertical;
  }

  .lsystem-two {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: .75rem;
  }

  .lsystem-head {
    display: flex;
    justify-content: space-between;
    align-items: start;
    gap: 1rem;
  }

  .lsystem-svg-wrap {
    border: 1px solid var(--line);
    background: var(--wash);
    overflow: auto;
  }

  #lsystem-plot {
    display: block;
    width: 100%;
    min-width: 38rem;
    height: 38rem;
  }

  .lsystem-output {
    border-top: 1px solid var(--line);
    padding-top: .75rem;
    font-variant-numeric: tabular-nums;
  }

  @media (max-width: 58rem) {
    .lsystem-grid { grid-template-columns: 1fr; }
  }
</style>

<style is:global>
  .lsystem-path { fill: none; stroke: var(--fg); stroke-linecap: round; stroke-linejoin: round; }
  .lsystem-frame { fill: none; stroke: var(--line); }
  .lsystem-label { fill: var(--muted); font-family: ui-monospace, monospace; }
</style>

<script>
  import '../scripts/lsystem.ts';
</script>

{
  "name": "site",
  "type": "module",
  "version": "0.0.1",
  "packageManager": "bun@1.3.13",
  "engines": {
    "node": ">=22.12.0"
  },
  "scripts": {
    "dev": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro dev",
    "build": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro build",
    "preview": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro preview",
    "check": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro check",
    "lint": "eslint src/scripts/**/*.ts",
    "astro": "cross-env ASTRO_TELEMETRY_DISABLED=1 astro"
  },
  "dependencies": {
    "@astrojs/vercel": "^11.0.0",
    "astro": "^7.0.0"
  },
  "devDependencies": {
    "@astrojs/check": "^0.9.9",
    "cross-env": "10.1.0",
    "eslint": "^10.4.1",
    "typescript": "^6.0.3",
    "typescript-eslint": "^8.61.0"
  }
}

:root {
  --bg: #fcfcfa;
  --fg: #171716;
  --muted: #716f68;
  --line: #e4e1d8;
  --wash: color-mix(in srgb, var(--bg) 94%, var(--fg));
  --accent: currentColor;
  --border: var(--line);
  --mono: inherit;
  --space: clamp(1rem, 4vw, 2.5rem);
  --measure: 38rem;
  font-family: ui-monospace, "SFMono-Regular", Menlo, Consolas, monospace;
}

* { box-sizing: border-box; }

body {
  margin: 0;
  background: var(--bg);
  color: var(--fg);
  font-size: 15px;
  line-height: 1.65;
  text-rendering: optimizeLegibility;
}

a {
  color: inherit;
  text-decoration: underline;
  text-decoration-color: var(--line);
  text-underline-offset: .25em;
}

a:hover { text-decoration-color: currentColor; }

h1, h2, h3, p, ul, ol { margin: 0 0 1rem; }

h1, h2, h3, strong { font-weight: 600; }

h1 {
  max-width: 13ch;
  font-size: clamp(2rem, 9vw, 5rem);
  line-height: .95;
  letter-spacing: -0.06em;
}

ul, ol { padding-left: 1.25rem; }

code {
  padding: .1em .3em;
  border: 1px solid var(--line);
  border-radius: 3px;
}

.app-shell, .canvas-app {
  min-height: 100dvh;
  background: var(--bg);
}

.app-shell { display: grid; grid-template-rows: auto 1fr; }
.canvas-app {
  position: relative;
  display: flex;
  flex-direction: column;
}

.equation-wallpaper {
  position: fixed;
  inset: 0;
  z-index: 0;
  overflow: hidden;
  pointer-events: none;
  color: var(--fg);
  opacity: .065;
}

.equation-wallpaper span {
  position: absolute;
  animation: equation-drift linear infinite;
  white-space: nowrap;
}

.canvas-app > :not(.equation-wallpaper) {
  position: relative;
  z-index: 1;
}

@keyframes equation-drift {
  from { transform: translate3d(-1rem, 0, 0) rotate(-6deg); }
  to { transform: translate3d(1rem, -4rem, 0) rotate(6deg); }
}

.control-panel {
  display: flex;
  align-items: center;
  gap: .6rem;
  padding: .55rem var(--space);
  border-bottom: 1px solid var(--line);
  background: color-mix(in srgb, var(--bg) 88%, transparent);
  backdrop-filter: blur(10px);
  flex-wrap: wrap;
}

.control-panel input[type="range"] { width: 8rem; }

.is-darkroom .canvas-app {
  background: #020202;
  color: #f5f2e8;
}

.is-darkroom .topbar,
.is-darkroom .control-panel {
  opacity: .08;
  transition: opacity .6s ease;
}

.is-darkroom .topbar:hover,
.is-darkroom .control-panel:hover { opacity: 1; }

.is-darkroom .canvas-stage::after {
  content: attr(id);
  position: absolute;
  left: var(--space);
  bottom: var(--space);
  color: currentColor;
  opacity: .35;
  animation: darkroom-label 3s ease both;
